import * as React from "react";

import { GuidewheelCircle } from "../assets/logos/GuidewheelCircle";
import { GuidewheelLogo } from "../assets/logos/GuidewheelLogo";
import { Tooltip, TooltipContent, TooltipTrigger } from "../tooltip/Tooltip";
import { cn } from "../utils/cn";

type NavItem = {
  id: string;
  label: string;
  icon?: React.ReactNode;
  href?: string;
  active?: boolean;
};

type NavigationSidebarProps = {
  /** Navigation items shown in the main area. */
  items: NavItem[];
  /** Whether the sidebar is collapsed to icon-only mode. */
  collapsed?: boolean;
  /** Callback fired when the sidebar collapse state should toggle. */
  onToggleCollapse?: () => void;
  /** Callback fired when a nav item is clicked. */
  onItemClick?: (item: NavItem) => void;
  /** Override the default logo element. */
  logo?: React.ReactNode;
  /** Company name displayed below the logo. */
  companyName?: string;
  /** Username displayed in the user menu area. */
  username?: string;
  /** Callback fired when the user clicks logout. */
  onLogout?: () => void;
  /** Help center URL. Defaults to `https://support.guidewheel.app`. */
  helpCenterUrl?: string;
  /** Collapse icon (shown when expanded). */
  collapseIcon?: React.ReactNode;
  /** Expand icon (shown when collapsed). */
  expandIcon?: React.ReactNode;
  /** Help icon for the help center link. */
  helpIcon?: React.ReactNode;
  /** User icon for the user menu area. */
  userIcon?: React.ReactNode;
  /** Additional CSS class name for the root element. */
  className?: string;
};

function NavItemButton({
  item,
  collapsed,
  onItemClick,
}: {
  item: NavItem;
  collapsed: boolean;
  onItemClick?: (item: NavItem) => void;
}) {
  const content = (
    <button
      data-slot="navigation-sidebar-item"
      data-active={item.active || undefined}
      className={cn(
        "flex w-full items-center gap-2 rounded px-3 py-1.5 text-sm font-medium",
        "transition-colors",
        "min-h-9",
        item.active
          ? "text-brand-secondary-500"
          : "text-brand-grey-800 hover:bg-white/[0.08]",
        collapsed && "justify-center px-0",
      )}
      onClick={() => onItemClick?.(item)}
    >
      {item.icon && (
        <span className="flex shrink-0 items-center justify-center size-[18px]">
          {item.icon}
        </span>
      )}
      {!collapsed && <span className="truncate">{item.label}</span>}
    </button>
  );

  if (collapsed) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>{content}</TooltipTrigger>
        <TooltipContent side="right">{item.label}</TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

/**
 * A collapsible sidebar navigation matching the Vue NavigationLayout.vue.
 *
 * Features:
 * - Edge-strip toggle on the right side of the sidebar
 * - Collapse/Expand nav item at the bottom
 * - Help Center link
 * - User menu with logout
 * - Company name below the logo
 *
 * Width: 150px expanded, 56px collapsed (matching Vue mini-variant).
 */
function NavigationSidebar({
  items,
  collapsed = false,
  onToggleCollapse,
  onItemClick,
  logo,
  companyName,
  username,
  onLogout,
  helpCenterUrl = "https://support.guidewheel.app",
  collapseIcon,
  expandIcon,
  helpIcon,
  userIcon,
  className,
}: NavigationSidebarProps) {
  return (
    <aside
      data-slot="navigation-sidebar"
      data-collapsed={collapsed || undefined}
      className={cn(
        "relative flex flex-col h-full bg-card pt-1",
        "transition-all duration-200",
        collapsed ? "w-14" : "w-[150px]",
        className,
      )}
    >
      {/* Edge-click collapse toggle — thin strip on the right edge */}
      <button
        data-slot="navigation-sidebar-edge-toggle"
        className={cn(
          "absolute top-0 -right-2 z-10 w-2 h-full",
          "bg-transparent transition-colors",
          "hover:bg-[rgba(241,194,50,0.3)] focus:bg-[rgba(241,194,50,0.4)]",
          collapsed ? "cursor-e-resize" : "cursor-w-resize",
        )}
        onClick={onToggleCollapse}
        aria-label={collapsed ? "Expand sidebar" : "Collapse sidebar"}
      />

      {/* Logo */}
      <div
        data-slot="navigation-sidebar-header"
        className={cn(
          "flex items-center px-3 py-2",
          collapsed ? "justify-center" : "px-4",
        )}
      >
        {logo ??
          (collapsed ? (
            <GuidewheelCircle className="size-8" aria-label="Guidewheel" />
          ) : (
            <GuidewheelLogo className="h-10 w-auto" aria-label="Guidewheel" />
          ))}
      </div>

      {/* Company name */}
      {companyName && !collapsed && (
        <div className="px-4 pb-1 text-xs font-bold capitalize text-brand-grey-800 break-words">
          {companyName}
        </div>
      )}

      {/* Nav items — no separator, matching Vue */}
      <nav
        data-slot="navigation-sidebar-nav"
        className="flex-1 overflow-y-auto px-1 py-1"
      >
        <ul className="flex flex-col" role="list">
          {items.map((item) => (
            <li key={item.id}>
              <NavItemButton
                item={item}
                collapsed={collapsed}
                onItemClick={onItemClick}
              />
            </li>
          ))}
        </ul>
      </nav>

      {/* Bottom section — Collapse, Help, User (matching Vue v-slot:append) */}
      <div data-slot="navigation-sidebar-footer" className="px-1 py-1">
        <ul className="flex flex-col" role="list">
          {/* Collapse / Expand item */}
          <li>
            <CollapseItem
              collapsed={collapsed}
              onToggleCollapse={onToggleCollapse}
              collapseIcon={collapseIcon}
              expandIcon={expandIcon}
            />
          </li>

          {/* Help Center link */}
          <li>
            <HelpCenterItem
              collapsed={collapsed}
              helpCenterUrl={helpCenterUrl}
              helpIcon={helpIcon}
            />
          </li>

          {/* User menu */}
          {username && (
            <li>
              <UserMenuItem
                collapsed={collapsed}
                username={username}
                onLogout={onLogout}
                userIcon={userIcon}
              />
            </li>
          )}
        </ul>
      </div>
    </aside>
  );
}

/** Collapse/Expand toggle nav item at the bottom of the sidebar. */
function CollapseItem({
  collapsed,
  onToggleCollapse,
  collapseIcon,
  expandIcon,
}: {
  collapsed: boolean;
  onToggleCollapse?: () => void;
  collapseIcon?: React.ReactNode;
  expandIcon?: React.ReactNode;
}) {
  const icon = collapsed ? expandIcon : collapseIcon;
  const label = collapsed ? "Expand" : "Collapse";

  const content = (
    <button
      data-slot="navigation-sidebar-collapse-item"
      className={cn(
        "flex w-full items-center gap-2 rounded px-3 py-1.5 text-sm font-medium",
        "text-brand-grey-800 transition-colors hover:bg-white/[0.08]",
        "min-h-9",
        collapsed && "justify-center px-0",
      )}
      onClick={onToggleCollapse}
    >
      {icon && (
        <span className="flex shrink-0 items-center justify-center size-[18px]">
          {icon}
        </span>
      )}
      {!collapsed && <span className="truncate">{label}</span>}
    </button>
  );

  if (collapsed) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>{content}</TooltipTrigger>
        <TooltipContent side="right">{label}</TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

/** Help Center external link item. */
function HelpCenterItem({
  collapsed,
  helpCenterUrl,
  helpIcon,
}: {
  collapsed: boolean;
  helpCenterUrl: string;
  helpIcon?: React.ReactNode;
}) {
  const label = "Help Center";

  const content = (
    <a
      data-slot="navigation-sidebar-help-item"
      href={helpCenterUrl}
      target="_blank"
      rel="noopener noreferrer"
      className={cn(
        "flex w-full items-center gap-2 rounded px-3 py-1.5 text-sm font-medium",
        "text-brand-grey-800 transition-colors hover:bg-white/[0.08]",
        "min-h-9 no-underline",
        collapsed && "justify-center px-0",
      )}
    >
      {helpIcon && (
        <span className="flex shrink-0 items-center justify-center size-[18px]">
          {helpIcon}
        </span>
      )}
      {!collapsed && <span className="truncate">{label}</span>}
    </a>
  );

  if (collapsed) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>{content}</TooltipTrigger>
        <TooltipContent side="right">{label}</TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

/** User menu item with optional logout action. */
function UserMenuItem({
  collapsed,
  username,
  onLogout,
  userIcon,
}: {
  collapsed: boolean;
  username: string;
  onLogout?: () => void;
  userIcon?: React.ReactNode;
}) {
  const [menuOpen, setMenuOpen] = React.useState(false);

  const content = (
    <div
      data-slot="navigation-sidebar-user-item"
      className={cn(
        "relative flex w-full items-center gap-2 rounded px-3 py-1.5 text-sm font-medium",
        "text-brand-grey-800 transition-colors hover:bg-white/[0.08]",
        "min-h-9 cursor-pointer",
        collapsed && "justify-center px-0",
      )}
      onMouseEnter={() => setMenuOpen(true)}
      onMouseLeave={() => setMenuOpen(false)}
    >
      {userIcon && (
        <span className="flex shrink-0 items-center justify-center size-[18px]">
          {userIcon}
        </span>
      )}
      {!collapsed && (
        <span
          className="truncate max-w-[80px]"
          title={username}
        >
          {username}
        </span>
      )}

      {/* Popover logout menu */}
      {menuOpen && onLogout && (
        <div
          className={cn(
            "absolute bg-white border border-[#ddd] rounded p-2 shadow-sm z-20",
            "flex items-center",
            collapsed ? "left-full ml-2 bottom-0" : "left-full ml-2 bottom-0",
          )}
        >
          <button
            className="text-sm text-brand-secondary-500 whitespace-nowrap hover:underline"
            onClick={(e) => {
              e.stopPropagation();
              onLogout();
            }}
          >
            Logout
          </button>
        </div>
      )}
    </div>
  );

  if (collapsed) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>{content}</TooltipTrigger>
        <TooltipContent side="right">{username}</TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

export { NavigationSidebar };
export type { NavItem, NavigationSidebarProps };
